/**
 * @summary Get data for public display screen
 */
export const getGetDisplayDataUrl = (queueId: number) => {
  return `/api/display/${queueId}`;
};

export const getDisplayData = async (
  queueId: number,
  options?: RequestInit,
): Promise<DisplayData> => {
  return customFetch<DisplayData>(getGetDisplayDataUrl(queueId), {
    ...options,
    method: "GET",
  });
};

export const getGetDisplayDataQueryKey = (queueId: number) => {
  return [`/api/display/${queueId}`] as const;
};

export const getGetDisplayDataQueryOptions = <
  TData = Awaited<ReturnType<typeof getDisplayData>>,
  TError = ErrorType<unknown>,
>(
  queueId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getDisplayData>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetDisplayDataQueryKey(queueId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getDisplayData>>> = ({
    signal,
  }) => getDisplayData(queueId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!queueId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getDisplayData>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetDisplayDataQueryResult = NonNullable<
  Awaited<ReturnType<typeof getDisplayData>>
>;
export type GetDisplayDataQueryError = ErrorType<unknown>;

